-- ============================================
-- GravHub CRM: HubSpot Import (Latest Export)
-- Generated 2026-07-06
-- 809 contacts, 820 companies, 71 deals
-- Uses ON CONFLICT (id) DO UPDATE for safe re-runs
-- ============================================

BEGIN;

-- Add name column to deals table if it doesn't exist
ALTER TABLE public.deals ADD COLUMN IF NOT EXISTS name text NOT NULL DEFAULT '';

-- ─── Companies (820 rows) ───


-- ─── Contacts (809 rows) ───


-- ─── Deals (71 rows) ───


-- ─── Resolve company_id on contacts by matching company_name to crm_companies.name ───
UPDATE crm_contacts ct
  SET company_id = co.id
  FROM crm_companies co
  WHERE ct.company_id IS NULL AND ct.company_name != '' AND ct.company_name = co.name;

-- ─── Resolve company_id on deals by matching company to crm_companies.name ───
UPDATE deals d
  SET company_id = co.id
  FROM crm_companies co
  WHERE d.company_id IS NULL AND d.company != '' AND d.company = co.name;

COMMIT;
